using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

namespace YourNamespace.Controllers
{
    [Route("api/[controller]")]
    [ApiController]
    public class FileUploadController : ControllerBase
    {
        private readonly string[] permittedExtensions = { ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".pdf", ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx" };
        private readonly long fileSizeLimit = 10 * 1024 * 1024; // 10 MB
        private readonly string uploadPath = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot/uploads");

        [HttpPost("upload")]
        public async Task<IActionResult> UploadFile(IFormFile file)
        {
            if (file == null || file.Length == 0)
                return BadRequest("No file uploaded.");

            var ext = Path.GetExtension(file.FileName).ToLowerInvariant();
            if (string.IsNullOrEmpty(ext) || !permittedExtensions.Contains(ext))
                return BadRequest("Invalid file type.");

            if (file.Length > fileSizeLimit)
                return BadRequest("File size exceeds limit.");

            var filePath = Path.Combine(uploadPath, Guid.NewGuid().ToString() + ext);

            try
            {
                Directory.CreateDirectory(uploadPath);
                using (var stream = new FileStream(filePath, FileMode.Create))
                {
                    await file.CopyToAsync(stream);
                }
            }
            catch (Exception ex)
            {
                return StatusCode(500, $"Internal server error: {ex.Message}");
            }

            return Ok(new { FilePath = filePath });
        }
    }
